SELECT h.id AS id, h.handover_by AS handoverBy, h.receive_by AS receiveBy, DATE_FORMAT(h.handover_time, '%Y-%m-%d %H:%i:%s') AS handoverTime, h.remark AS remark, h.item_names AS itemNames, h.create_by AS createBy, h.create_by_name AS createByName, DATE_FORMAT(h.create_time, '%Y-%m-%d %H:%i:%s') AS createTime, e1.name AS handoverByName, e2.name AS receiveByName FROM handover h LEFT JOIN employee e1 ON h.handover_by = e1.id LEFT JOIN employee e2 ON h.receive_by = e2.id
WHERE 1=1
and h.handover_by = #{empId,jdbcType=INTEGER} OR h.receive_by = #{empId,jdbcType=INTEGER} OR h.create_by = #{empId,jdbcType=INTEGER}
ORDER BY h.id DESC
limit #{page},#{size}

SELECT COUNT(*)
FROM handover h
WHERE 1=1

